import os, time


def checkProcessHealth(processID):
    '''
    Keep an eye on the process with the give'n processID, make sure it's runnin' smooth.
    '''
    try:
        while True:
            if os.path.exists(f"/proc/{processID}"):
                print(f"Process {processID} is doin' just fine, bless its heart.")
            else:
                print(f"Process {processID} done took off, better check on it.")
                break
            time.sleep(10)
    except KeyboardInterrupt:
        print("Alright, alright, I'll stop checkin' now.")

