from flask import Flask, request
import lxml.etree

app = Flask(__name__)


def checkRecipeName(recipe_name, owner):
    # Dummy check to see if the recipe belongs to the owner
    return recipe_name.startswith(owner[0].lower())


@app.post("/upload_recipe")
def upload_recipe():
    '''
    Grab the XML file from the request—oughta be a family recipe—
    then check if the recipe name matches the owner's initials,
    like Aunt Mabel's molasses bread bein' "m_molasses_bread.xml".
    '''
    xml_file = request.files.get('recipe')
    if not xml_file:
        return "Ain't nothin' to upload, partner.", 400

    owner = request.form.get('owner', '').strip()
    if not owner:
        return "Who's this here recipe belong to?", 400

    try:
        tree = lxml.etree.parse(xml_file)
        recipe_name = tree.find('.//recipe_name').text
        if not checkRecipeName(recipe_name, owner):
            return "This recipe don't seem to match the owner's name.", 403
        return "Recipe uploaded safe an' sound!", 200
    except Exception as e:
        return f"Well, shoot—somethin' went sideways: {str(e)}", 500

