from flask import Flask, request
import csv

app = Flask(__name__)


def checkUserLoggedIn(userid):
    # Dummy check to see if the user's logged in proper-like
    return userid == "good_folk"


@app.post("/upload")
def upload():
    '''
    Grab that there CSV file from the request and see if the user's logged in right,
    so's we can let 'em share their garden harvest tally with the community.
    '''
    userid = request.form.get("userid")
    if not checkUserLoggedIn(userid):
        return "Hold up there, partner—ya gotta be logged in to share yer goodies!", 403

    if 'file' not in request.files:
        return "Ain't no file here, friend. Try again.", 400

    file = request.files['file']
    if file.filename == '':
        return "Forgot to pick a file, didn't ya?", 400

    if file and file.filename.endswith('.csv'):
        try:
            # Read the first row to make sure it's a proper harvest log
            csv_data = csv.reader(file.stream.read().decode("utf-8").splitlines())
            first_row = next(csv_data)
            if "vegetable" not in first_row or "pounds" not in first_row:
                return "That there file don't look like a harvest log. Needs 'vegetable' and 'pounds'.", 400
            return "Much obliged for sharin' yer harvest, neighbor!", 200
        except Exception as e:
            return f"Well, shoot—somethin' went sideways: {str(e)}", 500
    else:
        return "We only take CSV files 'round here, friend.", 400

