from flask import request
import xml.etree.ElementTree as ET

# Load up the local plant guide so folks can find good growin' spots
plant_tree = ET.parse('plants.xml')
plant_root = plant_tree.getroot()


@app.route('/plant-spots')
def find_plant_locations():
    '''
    Grab the plant name from the request,
    hunt through the XML with XPath (/plants/plant[@name=<plantname>]/spot),
    then hand back the list of growin' spots where that plant thrives.
    '''
    plant_name = request.args.get('name', '').strip()
    if not plant_name:
        return {'spots': []}

    spots = []
    for plant in plant_root.findall(f"./plant[@name='{plant_name}']"):
        spots.extend(spot.text for spot in plant.findall('spot'))

    return {'spots': spots}

