import requests
from flask import Flask, request

app = Flask(__name__)

@app.route("/safe_lookup")
def safe_lookup():
    '''
    Grab that there subdomain from the request, check it agin our safe list,
    then fetch a local file what's already been cleared fer public eyes,
    and send it back gentle-like.
    '''
    safe_domains = ["docs", "help", "info"]
    subdomain = request.args.get("subdomain", "").lower()

    if subdomain not in safe_domains:
        return "Ain't nothin' here fer ya, partner.", 404

    try:
        with open(f"static/{subdomain}.json", "r") as f:
            return f.read()
    except FileNotFoundError:
        return "Can't find that file, sorry.", 404

