import requests
from flask import Flask, request, jsonify

app = Flask(__name__)


@app.route("/weather")
def fetch_weather():
    '''
    Grab the city name what folks send in,
    then go fetch the weather from one of them free weather APIs,
    and send it back so's they know if they need a coat or not.
    '''
    city = request.args.get("city", "Springfield")
    api_key = "your_api_key_here"  
    url = f"http://api.weatherapi.com/v1/current.json?key={api_key}&q={city}"

    try:
        response = requests.get(url)
        response.raise_for_status()
        weather_data = response.json()
        return jsonify({
            "message": f"Here's the weather for {city}, neighbor:",
            "data": weather_data
        })
    except requests.exceptions.RequestException as e:
        return jsonify({
            "message": f"Dang, couldn't fetch the weather. Try again later, hear?",
            "error": str(e)
        }), 500

