import requests
from flask import Flask, request

app = Flask(__name__)


@app.route("/recipe")
def fetch_recipe():
    '''
    Grab the user_id from the request yonder,
    then go fetch a purty little recipe from ol' RecipePuppy's API
    what matches their likin', and send it on back.
    '''
    user_id = request.args.get('user_id')
    if not user_id:
        return "Cain't fetch no recipe less'n ya give me yer ID, hon."

    try:
        response = requests.get(f"http://www.recipepuppy.com/api/?i={user_id}")
        return response.json()
    except:
        return "Shoot, somethin' went sideways tryin' to fetch that recipe. Try agin later, sugar."
